import {
  PasswordInput as PasswordInputPrimitive,
  usePasswordInput,
} from '@ark-ui/react/password-input';
import { clsx } from 'clsx';
import type { ComponentProps, ComponentRef } from 'react';
import { forwardRef } from 'react';
import { EyeClosedIcon, EyeIcon } from '@/lib/moduix/icons/ui';
import { normalizeClassName } from '@/lib/moduix/normalizeClassName';
import styles from './PasswordInput.module.css';

const PasswordInputRoot = forwardRef<
  ComponentRef<typeof PasswordInputPrimitive.Root>,
  ComponentProps<typeof PasswordInputPrimitive.Root>
>(function PasswordInputRoot({ className, ...props }, ref) {
  return (
    <PasswordInputPrimitive.Root
      ref={ref}
      data-slot="password-input-root"
      className={clsx(styles.root, normalizeClassName(className))}
      {...props}
    />
  );
});

const PasswordInputRootProvider = forwardRef<
  ComponentRef<typeof PasswordInputPrimitive.RootProvider>,
  ComponentProps<typeof PasswordInputPrimitive.RootProvider>
>(function PasswordInputRootProvider({ className, ...props }, ref) {
  return (
    <PasswordInputPrimitive.RootProvider
      ref={ref}
      data-slot="password-input-root-provider"
      className={clsx(styles.root, normalizeClassName(className))}
      {...props}
    />
  );
});

const PasswordInputLabel = forwardRef<
  ComponentRef<typeof PasswordInputPrimitive.Label>,
  ComponentProps<typeof PasswordInputPrimitive.Label>
>(function PasswordInputLabel({ className, ...props }, ref) {
  return (
    <PasswordInputPrimitive.Label
      ref={ref}
      data-slot="password-input-label"
      className={clsx(styles.label, normalizeClassName(className))}
      {...props}
    />
  );
});

const PasswordInputControl = forwardRef<
  ComponentRef<typeof PasswordInputPrimitive.Control>,
  ComponentProps<typeof PasswordInputPrimitive.Control>
>(function PasswordInputControl({ className, ...props }, ref) {
  return (
    <PasswordInputPrimitive.Control
      ref={ref}
      data-slot="password-input-control"
      className={clsx(styles.control, normalizeClassName(className))}
      {...props}
    />
  );
});

const PasswordInputInput = forwardRef<
  ComponentRef<typeof PasswordInputPrimitive.Input>,
  ComponentProps<typeof PasswordInputPrimitive.Input>
>(function PasswordInputInput({ className, ...props }, ref) {
  return (
    <PasswordInputPrimitive.Input
      ref={ref}
      data-slot="password-input-input"
      className={clsx(styles.input, normalizeClassName(className))}
      {...props}
    />
  );
});

const PasswordInputVisibilityTrigger = forwardRef<
  ComponentRef<typeof PasswordInputPrimitive.VisibilityTrigger>,
  ComponentProps<typeof PasswordInputPrimitive.VisibilityTrigger>
>(function PasswordInputVisibilityTrigger({ className, ...props }, ref) {
  return (
    <PasswordInputPrimitive.VisibilityTrigger
      ref={ref}
      data-slot="password-input-visibility-trigger"
      className={clsx(styles.visibilityTrigger, normalizeClassName(className))}
      {...props}
    />
  );
});

const PasswordInputIndicator = forwardRef<
  ComponentRef<typeof PasswordInputPrimitive.Indicator>,
  ComponentProps<typeof PasswordInputPrimitive.Indicator>
>(function PasswordInputIndicator({ className, children, fallback, ...props }, ref) {
  return (
    <PasswordInputPrimitive.Indicator
      ref={ref}
      data-slot="password-input-indicator"
      className={clsx(styles.indicator, normalizeClassName(className))}
      fallback={fallback ?? <EyeClosedIcon />}
      {...props}
    >
      {children ?? <EyeIcon />}
    </PasswordInputPrimitive.Indicator>
  );
});

type PasswordInputFieldProps = Omit<
  ComponentProps<typeof PasswordInputControl>,
  'asChild' | 'children'
>;

const PasswordInputField = forwardRef<
  ComponentRef<typeof PasswordInputPrimitive.Control>,
  PasswordInputFieldProps
>(function PasswordInputField(props, ref) {
  return (
    <PasswordInputControl ref={ref} {...props}>
      <PasswordInputInput />
      <PasswordInputVisibilityTrigger>
        <PasswordInputIndicator />
      </PasswordInputVisibilityTrigger>
    </PasswordInputControl>
  );
});

const PasswordInput = Object.assign(PasswordInputRoot, {
  Root: PasswordInputRoot,
  RootProvider: PasswordInputRootProvider,
  Label: PasswordInputLabel,
  Control: PasswordInputControl,
  Field: PasswordInputField,
  Input: PasswordInputInput,
  VisibilityTrigger: PasswordInputVisibilityTrigger,
  Indicator: PasswordInputIndicator,
});

export { PasswordInput, usePasswordInput };

@layer moduix.components {
  .root {
    box-sizing: border-box;
    display: flex;
    flex-direction: column;
    gap: var(--moduix-password-input-gap, var(--moduix-field-gap, var(--moduix-spacing-1)));
    width: var(--moduix-password-input-width, 100%);
    max-width: var(--moduix-password-input-max-width, 20rem);
    color: var(
      --moduix-password-input-color,
      var(--moduix-input-color, var(--moduix-color-foreground))
    );

    &[data-disabled] {
      opacity: var(
        --moduix-password-input-disabled-opacity,
        var(
          --moduix-field-disabled-opacity,
          var(--moduix-input-disabled-opacity, var(--moduix-opacity-disabled))
        )
      );
    }
  }

  .label {
    display: inline-flex;
    align-items: center;
    gap: var(
      --moduix-password-input-label-gap,
      var(--moduix-field-label-gap, var(--moduix-spacing-1))
    );
    color: var(
      --moduix-password-input-label-color,
      var(--moduix-field-label-color, var(--moduix-color-foreground))
    );
    font-size: var(
      --moduix-password-input-label-font-size,
      var(--moduix-field-label-font-size, var(--moduix-text-sm))
    );
    font-weight: var(
      --moduix-password-input-label-font-weight,
      var(--moduix-field-label-font-weight, var(--moduix-weight-medium))
    );
    line-height: var(
      --moduix-password-input-label-line-height,
      var(--moduix-field-label-line-height, var(--moduix-line-height-text-sm))
    );

    &[data-disabled] {
      opacity: var(
        --moduix-password-input-disabled-opacity,
        var(
          --moduix-field-disabled-opacity,
          var(--moduix-input-disabled-opacity, var(--moduix-opacity-disabled))
        )
      );
    }
  }

  .control {
    box-sizing: border-box;
    display: flex;
    align-items: center;
    width: 100%;
    min-height: var(
      --moduix-password-input-height,
      var(--moduix-input-height, var(--moduix-input-height-md, var(--moduix-size-md)))
    );
    border: var(--moduix-input-border-width, var(--moduix-border-width-sm))
      var(--moduix-input-border-style, solid)
      var(
        --moduix-password-input-border-color,
        var(--moduix-input-border-color, var(--moduix-color-border))
      );
    border-radius: var(
      --moduix-password-input-radius,
      var(--moduix-input-radius, var(--moduix-radius-md))
    );
    padding-inline-end: var(--moduix-password-input-trigger-inset, var(--moduix-spacing-2));
    background-color: var(
      --moduix-password-input-bg,
      var(--moduix-input-bg, var(--moduix-color-background))
    );
    color: var(
      --moduix-password-input-color,
      var(--moduix-input-color, var(--moduix-color-foreground))
    );
    outline: var(
        --moduix-input-focus-ring-width,
        var(--moduix-input-border-width, var(--moduix-border-width-sm))
      )
      solid transparent;
    outline-offset: var(
      --moduix-input-focus-ring-offset,
      calc(0px - var(--moduix-input-border-width, var(--moduix-border-width-sm)))
    );
    transition:
      border-color var(--moduix-input-transition, var(--moduix-transition-default)),
      outline-color var(--moduix-input-transition, var(--moduix-transition-default)),
      opacity var(--moduix-input-transition, var(--moduix-transition-default));

    &:focus-within {
      outline-color: var(
        --moduix-password-input-focus-ring-color,
        var(--moduix-input-focus-ring-color, var(--moduix-color-ring))
      );
    }

    &[data-invalid] {
      border-color: var(
        --moduix-password-input-invalid-border-color,
        var(--moduix-input-border-color-invalid, var(--moduix-color-destructive))
      );

      &:focus-within {
        outline-color: var(
          --moduix-password-input-invalid-focus-ring-color,
          var(--moduix-input-border-color-invalid, var(--moduix-color-destructive))
        );
      }
    }

    &[data-disabled] {
      opacity: var(
        --moduix-password-input-disabled-opacity,
        var(
          --moduix-field-disabled-opacity,
          var(--moduix-input-disabled-opacity, var(--moduix-opacity-disabled))
        )
      );
    }

    &[data-readonly] {
      background-color: var(
        --moduix-password-input-readonly-bg,
        var(--moduix-input-readonly-bg, var(--moduix-color-background))
      );
      color: var(
        --moduix-password-input-readonly-color,
        var(--moduix-input-readonly-color, var(--moduix-color-foreground))
      );
    }
  }

  .input {
    box-sizing: border-box;
    flex: 1 1 auto;
    min-width: 0;
    min-height: 0;
    margin: 0;
    border: 0;
    border-radius: 0;
    padding: var(
        --moduix-password-input-padding-y,
        var(--moduix-input-padding-y, var(--moduix-input-padding-y-md, var(--moduix-spacing-1)))
      )
      var(
        --moduix-password-input-padding-x,
        var(--moduix-input-padding-x, var(--moduix-input-padding-x-md, var(--moduix-spacing-3)))
      );
    background-color: transparent;
    color: var(
      --moduix-password-input-color,
      var(--moduix-input-color, var(--moduix-color-foreground))
    );
    font: inherit;
    font-size: var(
      --moduix-password-input-font-size,
      var(--moduix-input-font-size, var(--moduix-input-font-size-md, var(--moduix-text-md)))
    );
    line-height: var(
      --moduix-password-input-line-height,
      var(
        --moduix-input-line-height,
        var(--moduix-input-line-height-md, var(--moduix-line-height-text-md))
      )
    );
    outline: 0;
    transition: opacity var(--moduix-input-transition, var(--moduix-transition-default));

    &::placeholder {
      color: var(
        --moduix-password-input-placeholder-color,
        var(--moduix-input-placeholder-color, var(--moduix-color-muted-foreground))
      );
    }

    &:is([data-disabled], :disabled) {
      pointer-events: none;
      opacity: 1;
    }

    &:is(:read-only, [data-readonly]) {
      background-color: transparent;
    }
  }

  .visibilityTrigger {
    display: inline-flex;
    flex-shrink: 0;
    align-items: center;
    justify-content: center;
    width: var(
      --moduix-password-input-trigger-size,
      var(--moduix-button-size-sm, var(--moduix-size-sm))
    );
    min-width: var(
      --moduix-password-input-trigger-size,
      var(--moduix-button-size-sm, var(--moduix-size-sm))
    );
    height: var(
      --moduix-password-input-trigger-size,
      var(--moduix-button-size-sm, var(--moduix-size-sm))
    );
    padding: 0;
    color: var(--moduix-password-input-trigger-color, var(--moduix-color-muted-foreground));
    background: var(--moduix-password-input-trigger-bg, transparent);
    border: 0;
    border-radius: var(--moduix-password-input-trigger-radius, var(--moduix-radius-sm));
    outline: var(
        --moduix-input-focus-ring-width,
        var(--moduix-input-border-width, var(--moduix-border-width-sm))
      )
      solid transparent;
    outline-offset: var(
      --moduix-input-focus-ring-offset,
      calc(0px - var(--moduix-input-border-width, var(--moduix-border-width-sm)))
    );
    cursor: pointer;
    transition:
      color var(--moduix-input-transition, var(--moduix-transition-default)),
      outline-color var(--moduix-input-transition, var(--moduix-transition-default)),
      opacity var(--moduix-input-transition, var(--moduix-transition-default));

    &:hover {
      color: var(--moduix-password-input-trigger-hover-color, var(--moduix-color-foreground));
    }

    &:focus-visible {
      outline-color: var(
        --moduix-password-input-focus-ring-color,
        var(--moduix-input-focus-ring-color, var(--moduix-color-ring))
      );
    }

    &:is([data-disabled], :disabled) {
      opacity: 1;
    }
  }

  .indicator {
    display: inline-flex;
    align-items: center;
    justify-content: center;
    padding: var(--moduix-password-input-trigger-visual-padding, var(--moduix-spacing-1));
    border-radius: var(--moduix-password-input-trigger-radius, var(--moduix-radius-sm));
    transition:
      background-color var(--moduix-input-transition, var(--moduix-transition-default)),
      color var(--moduix-input-transition, var(--moduix-transition-default));

    & svg {
      width: var(
        --moduix-password-input-icon-size,
        var(--moduix-button-icon-size, var(--moduix-spacing-4))
      );
      height: var(
        --moduix-password-input-icon-size,
        var(--moduix-button-icon-size, var(--moduix-spacing-4))
      );
    }
  }

  .visibilityTrigger:hover .indicator,
  .visibilityTrigger:focus-visible .indicator {
    background: var(--moduix-password-input-trigger-hover-bg, var(--moduix-color-muted));
  }
}
